#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;package=org.archphene.linux.kcalc;timeout=30;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--package)package="${2:?}";shift 2;;--timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";component="$(archphene_launcher "$package")";archphene_adb_run logcat -c;archphene_adb_run shell am start -W -n "$component" >/dev/null;log="$(archphene_wait_log 'Capability broker listening' "$timeout" 'ArchpheneCapabilities AndroidRuntime *:S')";[[ "$log" != *'FATAL EXCEPTION'* ]] || archphene_die 'wrapper crashed';dump="$(archphene_adb_run shell dumpsys package "$package")";[[ "$dump" == *android.permission.POST_NOTIFICATIONS* ]] || archphene_die 'notification permission missing';archphene_note "Android capability broker passed on $serial: same-UID broker startup and permission contract verified."
